// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// writeErrorResponse writes a JSON error response with the specified status code and message.
func writeErrorResponse(ctx *fasthttp.RequestCtx, status int, message string) {
	resp := PreviewResponse{Error: message}
	b, err := json.Marshal(resp)
	if err != nil {
		ctx.Error("Internal server error", fasthttp.StatusInternalServerError)
		return
	}
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(status)
	ctx.Write(b)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		writeErrorResponse(ctx, fasthttp.StatusMethodNotAllowed, "Method not allowed")
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		writeErrorResponse(ctx, fasthttp.StatusBadRequest, "Invalid JSON")
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		writeErrorResponse(ctx, fasthttp.StatusBadRequest, "URL is required")
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		writeErrorResponse(ctx, fasthttp.StatusBadRequest, "Invalid URL format")
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		writeErrorResponse(ctx, fasthttp.StatusBadRequest, "URL must use http or https scheme")
		return
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		Timeout:             5 * time.Second, // Total timeout for entire request including redirects
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: 10 * 1024 * 1024, // 10MB
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html")

	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		if err == fasthttp.ErrBodyTooLarge {
			writeErrorResponse(ctx, fasthttp.StatusBadGateway, "Response body too large")
		} else if err == fasthttp.ErrTimeout {
			writeErrorResponse(ctx, fasthttp.StatusGatewayTimeout, "Request timed out")
		} else {
			writeErrorResponse(ctx, fasthttp.StatusBadGateway, fmt.Sprintf("Failed to fetch URL: %v", err))
		}
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		writeErrorResponse(ctx, fasthttp.StatusBadGateway, fmt.Sprintf("Unexpected status code: %d", res.StatusCode()))
		return
	}

	// Check if content is HTML
	contentType := strings.ToLower(string(res.Header.Peek("Content-Type")))
	if !strings.Contains(contentType, "text/html") {
		writeErrorResponse(ctx, fasthttp.StatusBadGateway, "Non-HTML content")
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		writeErrorResponse(ctx, fasthttp.StatusBadGateway, "Empty response body")
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		writeErrorResponse(ctx, fasthttp.StatusInternalServerError, fmt.Sprintf("Failed to parse HTML: %v", err))
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	b, err := json.Marshal(resp)
	if err != nil {
		writeErrorResponse(ctx, fasthttp.StatusInternalServerError, "Failed to encode response")
		return
	}
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.Write(b)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inHead := false
	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			if tokenizer.Err() == io.EOF {
				return title, description, nil
			}
			return "", "", tokenizer.Err()
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			if token.Data == "head" {
				inHead = true
			} else if token.Data == "body" {
				inHead = false
				// Stop parsing after body starts
				return title, description, nil
			}

			if inHead {
				if token.Data == "title" {
					// The next token should be the text for the title
					tt = tokenizer.Next()
					if tt == html.TextToken {
						title = tokenizer.Token().Data
					}
				} else if token.Data == "meta" {
					var isDescription bool
					var content string
					for _, attr := range token.Attr {
						if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
							isDescription = true
						} else if attr.Key == "content" {
							content = attr.Val
						}
					}
					if isDescription && content != "" {
						description = content
					}
				}
			}
		case html.EndTagToken:
			token := tokenizer.Token()
			if token.Data == "head" {
				inHead = false
				// Stop parsing after head ends
				return title, description, nil
			}
		}
	}
}

