// isAllowedHost checks if host is safe to access
func isAllowedHost(host string) bool {
	// Extract hostname without port
	hostname, _, err := net.SplitHostPort(host)
	if err != nil {
		hostname = host
	}

	// Block known restricted domains
	if strings.EqualFold(hostname, "localhost") || 
	   strings.HasSuffix(hostname, ".localhost") || 
	   strings.EqualFold(hostname, "internal") {
		return false
	}

	// Check if host is an IP address
	if ip := net.ParseIP(hostname); ip != nil {
		return !isPrivateIP(ip)
	}

	// Resolve domain to check IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return false
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return false
		}
	}
	return true
}

// isPrivateIP checks if IP is in private ranges
func isPrivateIP(ip net.IP) bool {
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 || 
		       (ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) || 
		       (ip4[0] == 192 && ip4[1] == 168) ||
		       ip4[0] == 127
	}
	// IPv6 private ranges
	return ip[0] == 0xfd || ip[0] == 0xfc
}

