	return title, description, nil
}

func parseHTMLMeta(content []byte) (string, string) {
	var title, description string
	doc, err := html.Parse(bytes.NewReader(content))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				if hasDescriptionAttribute(n) {
					for _, attr := range n.Attr {
						if attr.Key == "content" {
							description = attr.Val
							break
						}
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func hasDescriptionAttribute(n *html.Node) bool {
	for _, attr := range n.Attr {
		if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
			return true
		}
	}
	return false
}

func jsonResponse(ctx *fasthttp.RequestCtx, data interface{}, statusCode int) {
	ctx.Response.Header.Set("Content-Type", "application/json")
	ctx.Response.SetStatusCode(statusCode)
	if err := json.NewEncoder(ctx).Encode(data); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

