		res := fasthttp.AcquireResponse()
		defer fasthttp.ReleaseRequest(freq)
		defer fasthttp.ReleaseResponse(res)

		freq.SetRequestURI(targetURL)
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

		maxRedirectCounts := 10
		redirectCount := 0
		var lastErr error

		for {
			// Check for private IP before making request
			if err := checkPrivateIP(freq); err != nil {
				ctx.Error(fmt.Sprintf("Access to private IP blocked: %v", err), fasthttp.StatusForbidden)
				return
			}

			lastErr = client.Do(freq, res)
			if lastErr != nil {
				break
			}

			statusCode := res.StatusCode()
			if statusCode >= 300 && statusCode <= 399 {
				location := res.Header.Peek("Location")
				if len(location) == 0 {
					lastErr = fmt.Errorf("redirect with no Location header")
					break
				}

				redirectCount++
				if redirectCount > maxRedirectCounts {
					lastErr = fmt.Errorf("too many redirects")
					break
