			}

			if statusCode != fasthttp.StatusOK {
				lastErr = fmt.Errorf("unexpected status code: %d", statusCode)
				break
			}
			break
		}

		if lastErr != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", lastErr), fasthttp.StatusBadGateway)
			return
		}

		bodyBytes := res.Body()
