// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	queue := []*html.Node{doc}

	for len(queue) > 0 {
		node := queue[0]
		queue = queue[1:]

		if node.Type == html.ElementNode && node.Data == "head" {
			// Process the head node
			for child := node.FirstChild; child != nil; child = child.NextSibling {
				if child.Type == html.ElementNode && child.Data == "title" {
					if child.FirstChild != nil {
						title = child.FirstChild.Data
					}
				} else if child.Type == html.ElementNode && child.Data == "meta" {
					var metaName, content string
					for _, attr := range child.Attr {
						if attr.Key == "name" {
							metaName = attr.Val
						} else if attr.Key == "content" {
							content = attr.Val
						}
					}
					if strings.ToLower(metaName) == "description" {
						description = content
					}
				}
			}
			break
		}

		// Push children to the queue
		for c := node.FirstChild; c != nil; c = c.NextSibling {
			queue = append(queue, c)
		}
	}

	return title, description, nil
}

// checkPrivateIP validates if request host resolves to private IP
func checkPrivateIP(req *fasthttp.Request) error {
	host := string(req.URI().Host())
	ip := net.ParseIP(host)
	if ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("IP is private: %s", ip)
		}
		return nil
	}

	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
	if err != nil {
		return fmt.Errorf("failed to resolve host: %v", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("host resolved to private IP: %s", ip)
		}
	}
	return nil
}

// isPrivateIP checks if an IP address is in a private range
func isPrivateIP(ip net.IP) bool {
	if ip4 := ip.To4(); ip4 != nil {
		// Check for private IP ranges
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) ||
			ip4[0] == 127 ||
			(ip4[0] == 169 && ip4[1] == 254)
	}

	// Check for IPv6 private ranges
	ipv6 := ip.To16()
	if ipv6 != nil {
		return ipv6[0] == 0xfc || ipv6[0] == 0xfd || // fc00::/7 - unique local addresses
			(ipv6[0] == 0xfe && ipv6[1] == 0x80) // fe80::/10 - link-local
	}
	return false
}

// resolveRelativeURL resolves a relative URL against a base URL
func resolveRelativeURL(base, target string) (string, error) {
	baseURL, err := url.Parse(base)
	if err != nil {
		return "", err
	}
	targetURL, err := url.Parse(target)
	if err != nil {
		return "", err
	}
	return baseURL.ResolveReference(targetURL).String(), nil
}

