type responseBody struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

type errorResponse struct {
	Error string `json:"error"`
}

var client = &fasthttp.Client{
	Dial:         fasthttp.DialDualStack,
	ReadTimeout:  3 * time.Second,
	WriteTimeout: 3 * time.Second,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	var reqBody requestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(errorResponse{Error: "invalid JSON"})
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(errorResponse{Error: "url is required"})
		return
	}

	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(errorResponse{Error: "invalid URL format"})
		return
	}

	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	if err := client.DoRedirects(req, resp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(errorResponse{Error: "failed to fetch URL: " + err.Error()})
		return
	}

	if statusCode := resp.StatusCode(); statusCode < 200 || statusCode >= 300 {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(errorResponse{Error: "unexpected status code: " + string(resp.Header.StatusMessage())})
		return
	}

	title, description := parseHTML(resp.Body())
	json.NewEncoder(ctx).Encode(responseBody{
		Title:       title,
		Description: description,
	})
}

func parseHTML(content []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(content))
	if err != nil {
		return "", ""
	}

	var title, description string
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
