					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return title, description
}

func main() {
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		log.Fatalf("Error starting server: %s", err)
	}
