import (
	"encoding/json"
	"log"
	"strings"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/valyala/fasthttp"
)

// requestBody defines the structure for incoming JSON payload
type requestBody struct {
	URL string `json:"url"`
}

// previewData defines the structure for the JSON response
type previewData struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles POST requests to fetch URL preview metadata
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Verify request method is POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON request body
	var reqBody requestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.Error("Invalid JSON format", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL presence
	if reqBody.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// Configure HTTP client with dual-stack dialing and timeouts
	client := &fasthttp.Client{
		Dial:         fasthttp.DialDualStack,
		ReadTimeout:  5 * time.Second,
		WriteTimeout: 5 * time.Second,
	}

	// Create request and response objects
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	// Set request URL and headers
	req.SetRequestURI(reqBody.URL)
	req.Header.SetUserAgent("fasthttp")

	// Execute request with redirect handling and timeout
	if err := client.DoTimeout(req, resp, 5*time.Second); err != nil {
		ctx.Error("Failed to fetch URL", fasthttp.StatusInternalServerError)
		return
	}

	// Parse HTML response
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(resp.Body())))
	if err != nil {
		ctx.Error("Failed to parse HTML", fasthttp.StatusInternalServerError)
		return
	}

	// Extract metadata
	title := doc.Find("title").Text()
	description, _ := doc.Find("meta[name='description']").Attr("content")

	// Prepare and send JSON response
	responseData := previewData{
		Title:       title,
		Description: description,
	}
	responseJSON, err := json.Marshal(responseData)
	if err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.Write(responseJSON)
}

func main() {
	// Register handler and start server
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}

