// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inHead := false
	inTitle := false
	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			err = tokenizer.Err()
			if err == io.EOF {
				err = nil // we've reached the end, break
			}
			return title, description, err
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			if token.DataAtom == atom.Head && tokenType == html.StartTagToken {
				inHead = true
			}
			if !inHead {
				continue
			}
			if token.DataAtom == atom.Title {
				if tokenType == html.StartTagToken {
					inTitle = true
				}
			} else if token.DataAtom == atom.Meta {
				var contentVal string
				isDescription := false
				isOGDescription := false
				for _, attr := range token.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDescription = true
					} else if attr.Key == "property" && attr.Val == "og:description" {
						isOGDescription = true
					} else if attr.Key == "content" {
						contentVal = attr.Val
					}
				}
				if (isDescription || isOGDescription) && contentVal != "" {
					// Prefer og:description over standard description
					if isOGDescription || description == "" {
						description = contentVal
					}
				}
			}
		case html.TextToken:
			if inTitle {
				title = tokenizer.Token().Data
				inTitle = false // We only take the first text inside the title
			}
		case html.EndTagToken:
			token := tokenizer.Token()
			if token.DataAtom == atom.Head {
				inHead = false
				return title, description, nil
			} else if token.DataAtom == atom.Title {
				inTitle = false
			}
		}
	}
}

