}

type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

type errorResponse struct {
	Error string `json:"error"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		sendError(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req urlRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		sendError(ctx, "Invalid request body", fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		sendError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	client := &fasthttp.Client{
		Dial:         fasthttp.DialDualStack,
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	reqClient := fasthttp.AcquireRequest()
	respClient := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqClient)
	defer fasthttp.ReleaseResponse(respClient)

	reqClient.SetRequestURI(req.URL)
	reqClient.Header.SetUserAgent("Mozilla/5.0 (compatible; preview-bot)")

	if err := client.DoRedirects(reqClient, respClient, 10); err != nil {
		sendError(ctx, "Error fetching URL: "+err.Error(), fasthttp.StatusInternalServerError)
		return
	}

	if respClient.StatusCode() != fasthttp.StatusOK {
		sendError(ctx, "URL returned non-OK status", fasthttp.StatusBadGateway)
		return
	}

	doc, err := html.Parse(strings.NewReader(string(respClient.Body())))
	if err != nil {
		sendError(ctx, "Error parsing HTML", fasthttp.StatusInternalServerError)
		return
	}

	title, description := extractMetadata(doc)
	response := previewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(response); err != nil {
		sendError(ctx, "Error encoding response", fasthttp.StatusInternalServerError)
	}
}

func extractMetadata(n *html.Node) (title, description string) {
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			} else if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(n)
	return
}

func sendError(ctx *fasthttp.RequestCtx, message string, statusCode int) {
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(statusCode)
	errResp := errorResponse{Error: message}
	json.NewEncoder(ctx).Encode(errResp)
}

func main() {
	mux := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	log.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", mux); err != nil {
		log.Fatalf("Error starting server: %s", err)
	}
}

