// isGlobalIP checks if an IP address is globally routable and not in a private range.
func isGlobalIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return false
	}

	if ip4 := ip.To4(); ip4 != nil {
		switch {
		case ip4[0] == 10:
			return false
		case ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31:
			return false
		case ip4[0] == 192 && ip4[1] == 168:
			return false
		case ip4[0] == 169 && ip4[1] == 254:
			return false
		}
		return true
	}

	if ip6 := ip.To16(); ip6 != nil {
		if ip6[0] == 0xfc || ip6[0] == 0xfd {
			return false
		}
		return true
	}

	return false
}

// SafeDial restricts connections to globally routable IP addresses.
func SafeDial(addr string) (net.Conn, error) {
	dialer := &net.Dialer{
		Timeout: 5 * time.Second,
		Control: func(network, address string, conn syscall.RawConn) error {
			host, _, err := net.SplitHostPort(address)
			if err != nil {
				return err
			}
			ip := net.ParseIP(host)
			if ip == nil {
				return fmt.Errorf("invalid IP address: %s", host)
			}
			if !isGlobalIP(ip) {
				return fmt.Errorf("unsafe IP address: %s", ip)
			}
			return nil
		},
	}
	return dialer.Dial("tcp", addr)
}

