func main() {
	log.Fatal(fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/urlpreview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}))
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		sendError(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var reqBody struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		sendError(ctx, "Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	if reqBody.URL == "" {
		sendError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil {
		sendError(ctx, "Invalid URL", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		sendError(ctx, "URL scheme must be http or https", fasthttp.StatusBadRequest)
		return
	}

	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.SetTimeout(3 * time.Second)

	if err := client.DoRedirects(req, resp, 10); err != nil {
		if errors.Is(err, fasthttp.ErrTimeout) {
			sendError(ctx, "Request timeout", fasthttp.StatusRequestTimeout)
		} else {
			sendError(ctx, "Failed to fetch URL: "+err.Error(), fasthttp.StatusInternalServerError)
		}
		return
	}

	if resp.StatusCode() < 200 || resp.StatusCode() >= 300 {
		sendError(ctx, "Upstream returned non-2xx status", fasthttp.StatusBadGateway)
		return
	}

	doc, err := html.Parse(strings.NewReader(string(resp.Body())))
	if err != nil {
		sendError(ctx, "Failed to parse HTML", fasthttp.StatusInternalServerError)
		return
	}

	var title, description string
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				var isDescription bool
				var content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDescription = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDescription {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(struct {
		Title       string `json:"title"`
		Description string `json:"description"`
	}{
		Title:       title,
		Description: description,
	})
}

func sendError(ctx *fasthttp.RequestCtx, message string, status int) {
	ctx.SetStatusCode(status)
	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(struct {
		Error string `json:"error"`
	}{
		Error: message,
	})
}

