// safeDial checks if a host resolves to private IPs before connecting.
func safeDial(addr string) (net.Conn, error) {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, fmt.Errorf("invalid address")
	}

	ip := net.ParseIP(host)
	if ip != nil {
		if isPrivateIP(ip) {
