// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json; charset=utf-8")
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Method not allowed"})
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid request"})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL is required"})
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid URL"})
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL must use http or https scheme"})
		return
	}

	client := &fasthttp.Client{
		Dial:                safeDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: 10 * 1024 * 1024, // 10MB
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept-Encoding", "identity")

	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Failed to fetch URL"})
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Unexpected response from URL"})
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Empty response from URL"})
		return
	}

	contentType := res.Header.Peek("Content-Type")
	if !bytes.Contains(contentType, []byte("text/html")) {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL does not return HTML content"})
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Failed to parse HTML"})
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Failed to encode response"})
		return
	}
}

