// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if ctx.IsPost() {
		var req struct {
			URL string `json:"url"`
		}

		body := ctx.PostBody()
		if err := json.Unmarshal(body, &req); err != nil {
			ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
			return
		}

		targetURL := strings.TrimSpace(req.URL)
		if targetURL == "" {
			ctx.Error("URL is required", fasthttp.StatusBadRequest)
			return
		}

		// Validate URL scheme
		parsedURL, err := url.ParseRequestURI(targetURL)
		if err != nil {
			ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
			return
		}

		if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
			ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
			return
		}

		// Use fasthttp.Client to fetch with timeout
		client := &fasthttp.Client{
			Dial:               fasthttp.DialDualStack,
			ReadTimeout:        5 * time.Second,
			WriteTimeout:       5 * time.Second,
			MaxIdleConnDuration: 5 * time.Second,
			MaxConnsPerHost:    10,
		}

		freq := fasthttp.AcquireRequest()
		res := fasthttp.AcquireResponse()
		defer fasthttp.ReleaseRequest(freq)
		defer fasthttp.ReleaseResponse(res)

		freq.SetRequestURI(targetURL)
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

		// Total timeout for entire operation
		totalTimeout := 30 * time.Second
		startTime := time.Now()

		// Handle redirects manually
		var (
			statusCode int
			location   []byte
			redirects  int
			maxRedirects = 10
		)

		for {
			// Check total elapsed time
			if time.Since(startTime) > totalTimeout {
				ctx.Error("Total request timeout exceeded", fasthttp.StatusGatewayTimeout)
				return
			}

			// Resolve host to IPs
			host := string(freq.URI().Host())
			lookupCtx, lookupCancel := context.WithTimeout(context.Background(), 2*time.Second)
			ips, err := net.DefaultResolver.LookupIP(lookupCtx, "ip", host)
			lookupCancel()
			if err != nil {
				ctx.Error(fmt.Sprintf("Failed to resolve host: %v", err), fasthttp.StatusBadGateway)
				return
			}

			// Check for private IPs
			hasPrivate := false
			for _, ip := range ips {
				if isPrivateIP(ip) {
					hasPrivate = true
					break
				}
			}
			if hasPrivate {
				ctx.Error("URL resolves to a private IP", fasthttp.StatusForbidden)
				return
			}

			// Execute request
			if err := client.Do(freq, res); err != nil {
				ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
				return
			}

			statusCode = res.StatusCode()

			// Break if not redirect
			if statusCode < 300 || statusCode > 399 {
				break
			}

			// Handle redirect
			location = res.Header.Peek("Location")
			if len(location) == 0 {
				break
			}

			redirects++
			if redirects > maxRedirects {
				ctx.Error("Too many redirects", fasthttp.StatusBadGateway)
				return
			}

			// Set new location for next request
			freq.SetRequestURIBytes(location)
			res.Reset()
		}

		if statusCode != fasthttp.StatusOK {
			ctx.Error(fmt.Sprintf("Unexpected status code: %d", statusCode), fasthttp.StatusBadGateway)
			return
		}

		bodyBytes := res.Body()
		if len(bodyBytes) == 0 {
			ctx.Error("Empty response body", fasthttp.StatusBadGateway)
			return
		}

		title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
		if err != nil {
			ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
			return
		}

		resp := PreviewResponse{
			Title:       title,
			Description: description,
		}

		ctx.SetContentType("application/json; charset=utf-8")
		if err := json.NewEncoder(ctx).Encode(resp); err != nil {
			ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
			return
		}
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
