// isPrivateIP checks if an IP is in a private range
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() {
		return true
	}

	ip4 := ip.To4()
	if ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		return false
	}

	// IPv6 private ranges (fc00::/7)
	if len(ip) == net.IPv6len {
		if ip[0] == 0xfc || ip[0] == 0xfd {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	inHead := false
	inTitle := false
	var titleBuilder strings.Builder

	const maxTokens = 10000
	tokenCount := 0
	for tokenCount < maxTokens {
		tokenCount++
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return title, description, nil
			}
			return "", "", z.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			tok := z.Token()
			if tok.Data == "head" {
				inHead = true
			}
			if !inHead {
				continue
			}

			// If we are in the head and we encounter a body tag, then the head is over. Break the loop.
			if tok.Data == "body" {
				break
			}

			switch tok.Data {
			case "title":
				inTitle = true
				titleBuilder.Reset()
			case "meta":
				var metaName, metaContent string
				for _, attr := range tok.Attr {
					if attr.Key == "name" {
						metaName = attr.Val
					} else if attr.Key == "content" {
						metaContent = attr.Val
					}
				}
				if strings.EqualFold(metaName, "description") {
					description = metaContent
				}
			}

		case html.TextToken:
			if inTitle {
				titleBuilder.WriteString(z.Token().Data)
			}

		case html.EndTagToken:
			tok := z.Token()
			if tok.Data == "head" {
				// End of head, break the loop.
				break
			} else if tok.Data == "title" {
				if inTitle {
					title = strings.TrimSpace(titleBuilder.String())
					inTitle = false
				}
			}
		}
	}
	// Return what we have.
	return title, description, nil
}

