// FetchURLPreview handles URL preview requests
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set JSON content type for all responses
	ctx.SetContentType("application/json")

	// Parse request body
	var reqData requestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqData); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(errorResponse{Error: "Invalid JSON format"})
		return
	}

	// Validate URL
	if reqData.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(errorResponse{Error: "URL is required"})
		return
	}

	// Prepare HTTP request
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqData.URL)
	req.Header.SetMethod("GET")

	// Prepare response
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Execute request with redirects
	if err := client.DoRedirects(req, resp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(errorResponse{Error: "Failed to fetch URL: " + err.Error()})
		return
	}

	// Extract title and description
	title, description := extractMetadata(resp.Body())

	// Return successful response
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(previewData{
		Title:       title,
		Description: description,
	})
}

// extractMetadata parses HTML to find title and meta description
func extractMetadata(htmlContent []byte) (title, description string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	// Recursive node traversal function
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Process element nodes
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				// Check for description meta tag
				var isDescription bool
				var content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDescription = true
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDescription && description == "" {
					description = content
				}
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

