// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if ctx.IsPost() {
		var req struct {
			URL string `json:"url"`
		}

		body := ctx.PostBody()
		if err := json.Unmarshal(body, &req); err != nil {
			ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
			return
		}

		targetURL := strings.TrimSpace(req.URL)
		if targetURL == "" {
			ctx.Error("URL is required", fasthttp.StatusBadRequest)
			return
		}

		// Validate URL scheme
		parsedURL, err := url.ParseRequestURI(targetURL)
		if err != nil {
			ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
			return
		}

		if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
			ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
			return
		}

		// Use fasthttp.Client with safe dialer to block private IPs
		client := &fasthttp.Client{
			Dial:                safeDial,
			ReadTimeout:         10 * time.Second,
			WriteTimeout:        10 * time.Second,
			MaxIdleConnDuration: 10 * time.Second,
			MaxConnsPerHost:     10,
		}

		freq := fasthttp.AcquireRequest()
		res := fasthttp.AcquireResponse()
		defer fasthttp.ReleaseRequest(freq)
		defer fasthttp.ReleaseResponse(res)

		freq.SetRequestURI(targetURL)
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

		maxRedirectCounts := 10

		// Set a total timeout for the entire request including redirects.
		totalTimeout := 30 * time.Second
		timeoutChan := time.After(totalTimeout)
		errChan := make(chan error, 1)

		go func() {
			errChan <- client.DoRedirects(freq, res, maxRedirectCounts)
		}()

		select {
		case err := <-errChan:
			if err != nil {
				if strings.Contains(err.Error(), "private IP address") {
					ctx.Error("URL not allowed", fasthttp.StatusBadRequest)
					return
				}
				ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
				return
			}
		case <-timeoutChan:
			ctx.Error("Request timed out", fasthttp.StatusGatewayTimeout)
			return
		}

		if res.StatusCode() != fasthttp.StatusOK {
			ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
			return
		}

		bodyBytes := res.Body()
		if len(bodyBytes) == 0 {
			ctx.Error("Empty response body", fasthttp.StatusBadGateway)
			return
		}

		title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
		if err != nil {
			ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
			return
		}

		resp := PreviewResponse{
			Title:       title,
			Description: description,
		}

		ctx.SetContentType("application/json; charset=utf-8")
		if err := json.NewEncoder(ctx).Encode(resp); err != nil {
			ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
			return
		}
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// safeDial checks if the resolved IP is private and blocks the connection if it is.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve host with timeout
	dnsCtx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	ips, err := net.DefaultResolver.LookupIP(dnsCtx, "ip", host)
	if err != nil {
		return nil, err
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("private IP address: %s", ip.String())
		}
	}

	// Dial with timeout
	dialer := &net.Dialer{Timeout: 5 * time.Second}
	return dialer.Dial("tcp", net.JoinHostPort(ips[0].String(), port))
}

// isPrivateIP checks if the IP is in a private range.
func isPrivateIP(ip net.IP) bool {
	// IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) ||
			ip4[0] == 127
	}

	// IPv6 private ranges
	if ip.IsLoopback() {
		return true
	}
	if len(ip) >= 2 && ip[0] == 0xfe && ip[1]&0xc0 == 0x80 {
		return true
	}
	if len(ip) >= 2 && ip[0]&0xfe == 0xfc {
		return true
	}
	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	stack := []*html.Node{doc}
	titleFound := false
	descFound := false

	for len(stack) > 0 {
		node := stack[len(stack)-1]
		stack = stack[:len(stack)-1]

		if titleFound && descFound {
			break
		}

		if node.Type == html.ElementNode {
			if !titleFound && node.Data == "title" && node.FirstChild != nil {
				title = node.FirstChild.Data
				titleFound = true
			} else if !descFound && node.Data == "meta" {
				var isDescription bool
				var content string
				for _, attr := range node.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDescription = true
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDescription && content != "" {
					description = content
					descFound = true
				}
			}
		}

		if node.FirstChild != nil {
			children := make([]*html.Node, 0, 10)
			for c := node.FirstChild; c != nil; c = c.NextSibling {
				children = append(children, c)
			}
			for i := len(children) - 1; i >= 0; i-- {
				stack = append(stack, children[i])
			}
		}
	}

	return title, description, nil
}

