// dialWithSSRFProtection resolves host and checks for private IPs before dialing
func dialWithSSRFProtection(addr string) (net.Conn, error) {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("private IP address: %s", ip.String())
		}
	}

	return fasthttp.DialDualStack(addr)
}

// isPrivateIP checks if an IP address belongs to private networks
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() {
		return true
	}

	ip4 := ip.To4()
	if ip4 != nil {
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) ||
			(ip4[0] == 169 && ip4[1] == 254) // link-local
	}

	if len(ip) == net.IPv6len {
		if ip[0] == 0xfc || ip[0] == 0xfd { // fc00::/7 - unique local address
			return true
		}
		if ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 { // fe80::/10 - link-local
			return true
		}
	}

	return false
}

