func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON request body
	var reqBody requestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.Error("Invalid JSON format", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format
	if reqBody.URL == "" {
		ctx.Error("Missing URL field", fasthttp.StatusBadRequest)
		return
	}
	if _, err := url.ParseRequestURI(reqBody.URL); err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	// Create fasthttp client with dual-stack dialer and timeouts
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			dialer := &net.Dialer{
				Timeout:   3 * time.Second,
				DualStack: true,
			}
			return dialer.Dial("tcp", addr)
		},
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Prepare request and response objects
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	// Set up request
	req.SetRequestURI(reqBody.URL)
	req.Header.SetUserAgent("fasthttp")

	// Execute request with redirect handling (max 10 redirects)
	if err := client.DoRedirects(req, resp, 10); err != nil {
		ctx.Error("Failed to fetch URL", fasthttp.StatusInternalServerError)
		return
	}

	// Check for valid response status
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.Error("Failed to fetch URL content", fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body())

	// Prepare and send JSON response
	preview := previewResponse{
		Title:       title,
		Description: description,
	}
	jsonData, err := json.Marshal(preview)
	if err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.Write(jsonData)
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(content []byte) (string, string) {
	var title, description string

	// Create tokenizer from HTML content
	tokenizer := html.NewTokenizer(strings.NewReader(string(content)))

	// Flag to stop parsing after </head> to improve efficiency
	stopParsing := false

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			break
		}

		token := tokenizer.Token()
		if token.Type == html.StartTagToken {
			if token.Data == "body" {
				stopParsing = true
			}
		}

		if stopParsing {
			break
		}

		// Process title tag
		if token.Data == "title" && token.Type == html.StartTagToken {
			tokenType = tokenizer.Next()
			if tokenType == html.TextToken {
				title = strings.TrimSpace(tokenizer.Token().Data)
			}
		}

		// Process meta tags
		if token.Data == "meta" {
			var metaName, metaContent string
			for _, attr := range token.Attr {
				if attr.Key == "name" {
					metaName = attr.Val
				}
				if attr.Key == "content" {
					metaContent = attr.Val
				}
			}
			if metaName == "description" {
				description = metaContent
			}
		}
	}

	return title, description
}

func main() {
	// Configure request routing
	router := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/fetch-url-preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

