package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if ctx.IsPost() {
		var req struct {
			URL string `json:"url"`
		}

		body := ctx.PostBody()
		if err := json.Unmarshal(body, &req); err != nil {
			ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
			return
		}

		targetURL := strings.TrimSpace(req.URL)
		if targetURL == "" {
			ctx.Error("URL is required", fasthttp.StatusBadRequest)
			return
		}

		// Validate URL scheme and private IP
		if err := validateURL(targetURL); err != nil {
			ctx.Error(fmt.Sprintf("Invalid URL: %v", err), fasthttp.StatusBadRequest)
			return
		}

		// Use fasthttp.Client to fetch with timeout
		client := &fasthttp.Client{
			Dial:                fasthttp.DialDualStack,
			ReadTimeout:         10 * time.Second,
			WriteTimeout:        10 * time.Second,
			MaxIdleConnDuration: 10 * time.Second,
			MaxConnsPerHost:     10,
			MaxResponseBodySize: 2 * 1024 * 1024, // 2MB limit
		}

		freq := fasthttp.AcquireRequest()
		res := fasthttp.AcquireResponse()
		defer fasthttp.ReleaseRequest(freq)
		defer fasthttp.ReleaseResponse(res)

		freq.SetRequestURI(targetURL)
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

		currentURL := targetURL
		redirectCount := 0
		maxRedirects := 10
		for {
			if err := client.Do(freq, res); err != nil {
				ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
				return
			}

			statusCode := res.StatusCode()
			if statusCode >= 300 && statusCode < 400 {
				redirectCount++
				if redirectCount > maxRedirects {
					ctx.Error("Too many redirects", fasthttp.StatusBadGateway)
					return
				}

				location := res.Header.Peek("Location")
				if len(location) == 0 {
					ctx.Error("Redirect missing Location header", fasthttp.StatusBadGateway)
					return
				}

				nextURL := resolveRelativeURL(currentURL, string(location))
				if err := validateURL(nextURL); err != nil {
					ctx.Error(fmt.Sprintf("Invalid redirect URL: %v", err), fasthttp.StatusBadGateway)
					return
				}

				// Prepare for next request
				currentURL = nextURL
				freq.Reset()
				res.Reset()
				freq.SetRequestURI(nextURL)
				freq.Header.SetMethod("GET")
				freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
				continue
			}

			if statusCode != fasthttp.StatusOK {
				ctx.Error(fmt.Sprintf("Unexpected status code: %d", statusCode), fasthttp.StatusBadGateway)
				return
			}

			break
		}

		bodyBytes := res.Body()
		if len(bodyBytes) == 0 {
			ctx.Error("Empty response body", fasthttp.StatusBadGateway)
			return
		}

		title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
		if err != nil {
			ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
			return
		}

		resp := PreviewResponse{
			Title:       title,
			Description: description,
		}

		ctx.SetContentType("application/json; charset=utf-8")
		if err := json.NewEncoder(ctx).Encode(resp); err != nil {
			ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
			return
		}
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// validateURL checks if URL has valid scheme and doesn't resolve to private IP
func validateURL(rawURL string) error {
	u, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	if u.Scheme != "http" && u.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	host := u.Hostname()
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve host")
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("URL resolves to a private IP")
		}
	}
	return nil
}

// isPrivateIP checks if IP belongs to private ranges
func isPrivateIP(ip net.IP) bool {
	return ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
}

// resolveRelativeURL converts relative URL to absolute based on base URL
func resolveRelativeURL(base, relative string) string {
	baseURL, err := url.Parse(base)
	if err != nil {
		return relative
	}
	refURL, err := url.Parse(relative)
	if err != nil {
		return relative
	}
	return baseURL.ResolveReference(refURL).String()
}

// parseHTMLPreview extracts title and meta description from HTML
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inHead := false

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			if tokenizer.Err() == io.EOF {
				return title, description, nil
			}
			return "", "", tokenizer.Err()

		case html.StartTagToken, html.SelfClosingTagToken, html.EndTagToken:
			token := tokenizer.Token()
			switch token.Data {
			case "head":
				if tokenType == html.StartTagToken {
					inHead = true
				} else if tokenType == html.EndTagToken {
					inHead = false
				}
			case "body":
				if tokenType == html.StartTagToken {
					inHead = false
				}
			}

			if !inHead {
				if token.Data == "body" && tokenType == html.StartTagToken {
					return title, description, nil
				}
				continue
			}

			if token.Data == "title" && tokenType == html.StartTagToken && title == "" {
				if next := tokenizer.Next(); next == html.TextToken {
					title = tokenizer.Token().Data
				}
			}

			if token.Data == "meta" && (tokenType == html.StartTagToken || tokenType == html.SelfClosingTagToken) {
				var isDescription bool
				var content string
				for _, attr := range token.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDescription = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDescription && description == "" {
					description = content
				}
			}
		}
	}
}

