	"golang.org/x/net/html"
)

type Request struct {
	URL string `json:"url"`
}

type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Validate request method
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse JSON body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid request body", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		ctx.Error("Invalid URL", fasthttp.StatusBadRequest)
		return
	}

	// Configure HTTP client with timeout
	client := &fasthttp.Client{
		Dial:         fasthttp.DialDualStack,
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}
	reqCtx := &fasthttp.Request{}
	respCtx := &fasthttp.Response{}
	reqCtx.SetRequestURI(req.URL)

	// Execute request with redirects
	if err := client.DoRedirects(reqCtx, respCtx, 10); err != nil {
		ctx.Error(fmt.Sprintf("Fetch error: %s", err), fasthttp.StatusInternalServerError)
		return
	}

	// Parse HTML content
	doc, err := html.Parse(strings.NewReader(string(respCtx.Body())))
	if err != nil {
		ctx.Error("HTML parse error", fasthttp.StatusInternalServerError)
		return
	}

	// Extract metadata
	title, description := extractMetadata(doc)
	res := Response{
		Title:       title,
		Description: description,
	}

	// Return JSON response
	resJSON, _ := json.Marshal(res)
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.Write(resJSON)
}

func extractMetadata(n *html.Node) (title, description string) {
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			if n.Data == "meta" {
				var desc, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						desc = "found"
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if desc != "" && content != "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(n)
	return
}

func main() {
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
