package main

import (
	"encoding/json"
	"log"
	"net"
	"strings"
	"syscall"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/valyala/fasthttp"
)

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	}

	log.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		log.Fatalf("Server failed: %s", err)
	}
}

func isPrivateIP(ip net.IP) bool {
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) ||
			(ip4[0] == 169 && ip4[1] == 254)
	}
	return len(ip) == net.IPv6len && ip[0]&0xfe == 0xfc
}

func safeDial(addr string) (net.Conn, error) {
	dialer := &net.Dialer{
		Timeout: 5 * time.Second,
		Control: func(_, address string, _ syscall.RawConn) error {
			host, _, err := net.SplitHostPort(address)
			if err != nil {
				return err
			}
			ip := net.ParseIP(host)
			if ip == nil {
				return nil
			}
			if isPrivateIP(ip) || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
				return syscall.EPERM
			}
			return nil
		},
	}
	return dialer.Dial("tcp", addr)
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	client := &fasthttp.Client{
		Dial:            safeDial,
		ReadTimeout:     5 * time.Second,
		WriteTimeout:    5 * time.Second,
		MaxConnsPerHost: 100,
	}
	defer client.CloseIdleConnections()

	reqClient := fasthttp.AcquireRequest()
	respClient := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqClient)
	defer fasthttp.ReleaseResponse(respClient)

	reqClient.SetRequestURI(req.URL)
	if err := client.DoRedirects(reqClient, respClient, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(map[string]string{"error": err.Error()})
		return
	}

	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(respClient.Body())))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(map[string]string{"error": "Failed to parse HTML"})
		return
	}

	title := doc.Find("title").Text()
	description, _ := doc.Find("meta[name='description']").Attr("content")

	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(map[string]string{
		"title":       title,
		"description": description,
	})
}

