package main

import (
	"bytes"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

func main() {
	addr := ":8080"
	log.Printf("Server listening on %s", addr)
	if err := fasthttp.ListenAndServe(addr, requestRouter); err != nil {
		log.Fatalf("Error in ListenAndServe: %v", err)
	}
}

func requestRouter(ctx *fasthttp.RequestCtx) {
	switch string(ctx.Path()) {
	case "/urlpreview":
		FetchURLPreview(ctx)
	default:
		ctx.Error("Not found", fasthttp.StatusNotFound)
	}
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		sendError(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		sendError(ctx, "Invalid JSON format", fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		sendError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	if _, err := url.ParseRequestURI(req.URL); err != nil {
		sendError(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
		MaxRedirectsCount: 10,
		ReadTimeout: 5 * time.Second,
		WriteTimeout: 5 * time.Second,
	}

	request := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(request)
	request.SetRequestURI(req.URL)
	request.Header.SetUserAgent("Mozilla/5.0 (compatible; preview-bot/1.0)")

	response := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(response)

	if err := client.Do(request, response); err != nil {
		sendError(ctx, fmt.Sprintf("Error fetching URL: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	contentType := string(response.Header.ContentType())
	if !strings.Contains(contentType, "text/html") {
		sendError(ctx, "URL content is not HTML", fasthttp.StatusBadRequest)
		return
	}

	title, description, err := parseHTMLContent(response.Body())
	if err != nil {
		sendError(ctx, fmt.Sprintf("Error parsing HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(map[string]string{
		"title":       title,
		"description": description,
	})
}

func parseHTMLContent(body []byte) (string, string, error) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", "", err
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				desc := ""
				isDesc := false
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						isDesc = true
					}
					if attr.Key == "content" && isDesc {
						desc = attr.Val
					}
				}
				if desc != "" && description == "" {
					description = desc
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	if title == "" && description == "" {
		return "", "", errors.New("no title or description found")
	}
	return title, description, nil
}

func sendError(ctx *fasthttp.RequestCtx, message string, status int) {
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(status)
	json.NewEncoder(ctx).Encode(map[string]string{"error": message})
}

